import{_ as e,o as a,c as o,a2 as s}from"./chunks/framework.Crpw6aS5.js";const r="/assets/community-scripts-logo.ByLJE9nx.png",u=JSON.parse('{"title":"Proxmox VE Helper Scripts (community-scripts.org)","description":"Notes on Proxmox VE Helper Scripts (community-scripts.org).","frontmatter":{"title":"Proxmox VE Helper Scripts (community-scripts.org)","description":"Notes on Proxmox VE Helper Scripts (community-scripts.org)."},"headers":[],"relativePath":"snippets-and-scripts/scripts/community-scripts-org/README.md","filePath":"snippets-and-scripts/scripts/community-scripts-org/README.md"}'),i={name:"snippets-and-scripts/scripts/community-scripts-org/README.md"};function d(n,t,h,l,c,p){return a(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="proxmox-ve-helper-scripts-community-scripts-org" tabindex="-1">Proxmox VE Helper Scripts (community-scripts.org) <a class="header-anchor" href="#proxmox-ve-helper-scripts-community-scripts-org" aria-label="Permalink to &quot;Proxmox VE Helper Scripts (community-scripts.org)&quot;">​</a></h1><p><img src="'+r+'" alt="Proxmox VE Helper Scripts logo"></p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://community-scripts.org/" target="_blank" rel="noreferrer">https://community-scripts.org/</a></li><li>Upstream repo: <a href="https://github.com/community-scripts/ProxmoxVE" target="_blank" rel="noreferrer">https://github.com/community-scripts/ProxmoxVE</a></li><li>Imported: 2026-06-11</li><li>Images: logo saved locally under <code>./assets/</code></li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p><a href="https://community-scripts.org/" target="_blank" rel="noreferrer">community-scripts.org</a> is the browseable catalog for <strong>Proxmox VE Helper Scripts</strong> — community-maintained automation that creates LXCs, VMs, and host add-ons from the Proxmox shell. The project builds on <a href="https://github.com/tteck" target="_blank" rel="noreferrer">@tteck</a>&#39;s original helper-script work.</p><p>Rough scale (from the site homepage): <strong>598 scripts</strong>, <strong>26 categories</strong>, millions of installs.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Details</th></tr></thead><tbody><tr><td>Proxmox VE</td><td>8.4, 9.0, 9.1, or 9.2</td></tr><tr><td>Host</td><td>Proxmox VE (Debian-based)</td></tr><tr><td>Access</td><td>Root shell on the Proxmox node</td></tr><tr><td>Network</td><td>Internet during install</td></tr></tbody></table><h3 id="how-to-use" tabindex="-1">How to use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to use&quot;">​</a></h3><ol><li>Open <a href="https://community-scripts.org/" target="_blank" rel="noreferrer">community-scripts.org</a> and search for a service.</li><li>Copy the <strong>one-line install command</strong> from the script page (or use the paths below).</li><li>Paste into the <strong>Proxmox node shell</strong> (not inside an existing LXC unless the script says so).</li><li>Choose <strong>Default</strong> (sensible CPU/RAM/disk) or <strong>Advanced</strong> (full control).</li><li>After install, many LXCs expose an <strong>update/settings helper</strong> when you open the container shell from Proxmox.</li></ol><h3 id="install-command-pattern" tabindex="-1">Install command pattern <a class="header-anchor" href="#install-command-pattern" aria-label="Permalink to &quot;Install command pattern&quot;">​</a></h3><p>Replace <code>PATH/TO/script.sh</code> with a path from the tables below (<code>ct/</code>, <code>vm/</code>, <code>tools/pve/</code>, or <code>tools/addon/</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -qLO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> - https://github.com/community-scripts/ProxmoxVE/raw/main/PATH/TO/script.sh)&quot;</span></span></code></pre></div><p>Alternative using <code>curl</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/community-scripts/ProxmoxVE/main/PATH/TO/script.sh)&quot;</span></span></code></pre></div><blockquote><p><strong>Tip:</strong> Prefer copying the exact command from the script&#39;s page on community-scripts.org when available — paths and flags can change.</p></blockquote><hr><h2 id="curated-examples" tabindex="-1">Curated examples <a class="header-anchor" href="#curated-examples" aria-label="Permalink to &quot;Curated examples&quot;">​</a></h2><p>Hand-picked scripts that cover common homelab needs. Full catalog: <a href="https://community-scripts.org/categories" target="_blank" rel="noreferrer">community-scripts.org/categories</a>.</p><h3 id="reverse-proxy-dns" tabindex="-1">Reverse proxy &amp; DNS <a class="header-anchor" href="#reverse-proxy-dns" aria-label="Permalink to &quot;Reverse proxy &amp; DNS&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Type</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Nginx Proxy Manager</strong></td><td>LXC</td><td><code>ct/nginxproxymanager.sh</code></td><td>Web UI for reverse proxies, TLS, hostnames — often what people mean by “proxy manager” on Proxmox</td></tr><tr><td>AdGuard Home</td><td>LXC</td><td><code>ct/adguard.sh</code></td><td>Network-wide DNS filtering / ad blocking</td></tr><tr><td>Pi-hole</td><td>LXC</td><td><code>ct/pihole.sh</code></td><td>DNS sinkhole</td></tr><tr><td>Traefik</td><td>LXC</td><td><code>ct/traefik.sh</code></td><td>Dynamic reverse proxy / ingress</td></tr></tbody></table><p><strong>Nginx Proxy Manager</strong> example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -qLO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> - https://github.com/community-scripts/ProxmoxVE/raw/main/ct/nginxproxymanager.sh)&quot;</span></span></code></pre></div><h3 id="proxmox-host-lxc-maintenance" tabindex="-1">Proxmox host &amp; LXC maintenance <a class="header-anchor" href="#proxmox-host-lxc-maintenance" aria-label="Permalink to &quot;Proxmox host &amp; LXC maintenance&quot;">​</a></h3><p>Run these on the <strong>Proxmox host</strong> (not inside a service LXC).</p><table tabindex="0"><thead><tr><th>Tool</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td>Post-PVE install</td><td><code>tools/pve/post-pve-install.sh</code></td><td>Recommended after fresh PVE install — repos, updates, common tweaks</td></tr><tr><td>Update all LXCs</td><td><code>tools/pve/update-lxcs.sh</code></td><td>Batch-update containers created by helper scripts</td></tr><tr><td>Host backup</td><td><code>tools/pve/host-backup.sh</code></td><td>Backup helper for the node</td></tr><tr><td>LXC execute</td><td><code>tools/pve/execute.sh</code></td><td>Run a command across selected LXCs</td></tr><tr><td>All templates</td><td><code>tools/addon/all-templates.sh</code></td><td>Create base LXC OS templates (Debian, Ubuntu, Alpine, …)</td></tr><tr><td>Webmin</td><td><code>tools/addon/webmin.sh</code></td><td>Browser-based server admin</td></tr></tbody></table><p><strong>Post-PVE install</strong> (good first step on a new node):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -qLO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> - https://github.com/community-scripts/ProxmoxVE/raw/main/tools/pve/post-pve-install.sh)&quot;</span></span></code></pre></div><h3 id="base-os-containers" tabindex="-1">Base OS &amp; containers <a class="header-anchor" href="#base-os-containers" aria-label="Permalink to &quot;Base OS &amp; containers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Type</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td>Docker (in LXC)</td><td>LXC</td><td><code>ct/docker.sh</code></td><td>Docker engine inside an unprivileged LXC</td></tr><tr><td>Debian template LXC</td><td>LXC</td><td><code>ct/debian.sh</code></td><td>Minimal Debian container</td></tr><tr><td>Ubuntu template LXC</td><td>LXC</td><td><code>ct/ubuntu.sh</code></td><td>Minimal Ubuntu container</td></tr></tbody></table><h3 id="home-automation-smart-home" tabindex="-1">Home automation &amp; smart home <a class="header-anchor" href="#home-automation-smart-home" aria-label="Permalink to &quot;Home automation &amp; smart home&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Type</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td>Home Assistant OS</td><td>VM</td><td><code>vm/haos-vm.sh</code></td><td>Official HAOS qcow2 VM image</td></tr><tr><td>Home Assistant (container)</td><td>LXC</td><td><code>ct/homeassistant.sh</code></td><td>HA Core in LXC (not full HAOS)</td></tr></tbody></table><h3 id="media-photos-nvr" tabindex="-1">Media, photos &amp; NVR <a class="header-anchor" href="#media-photos-nvr" aria-label="Permalink to &quot;Media, photos &amp; NVR&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Type</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td>Immich</td><td>LXC</td><td><code>ct/immich.sh</code></td><td>Self-hosted photos/video</td></tr><tr><td>Jellyfin</td><td>LXC</td><td><code>ct/jellyfin.sh</code></td><td>Media server</td></tr><tr><td>Frigate</td><td>LXC</td><td><code>ct/frigate.sh</code></td><td>AI NVR for IP cameras</td></tr></tbody></table><h3 id="monitoring-automation-ai" tabindex="-1">Monitoring, automation &amp; AI <a class="header-anchor" href="#monitoring-automation-ai" aria-label="Permalink to &quot;Monitoring, automation &amp; AI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Type</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td>Uptime Kuma</td><td>LXC</td><td><code>ct/uptimekuma.sh</code></td><td>Status / uptime monitoring</td></tr><tr><td>Grafana</td><td>LXC</td><td><code>ct/grafana.sh</code></td><td>Dashboards &amp; visualization</td></tr><tr><td>n8n</td><td>LXC</td><td><code>ct/n8n.sh</code></td><td>Workflow automation</td></tr><tr><td>Ollama</td><td>LXC</td><td><code>ct/ollama.sh</code></td><td>Local LLM inference</td></tr></tbody></table><h3 id="security-passwords" tabindex="-1">Security &amp; passwords <a class="header-anchor" href="#security-passwords" aria-label="Permalink to &quot;Security &amp; passwords&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Type</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td>Vaultwarden</td><td>LXC</td><td><code>ct/vaultwarden.sh</code></td><td>Bitwarden-compatible password vault</td></tr></tbody></table><h3 id="docker-paas-add-ons-on-host" tabindex="-1">Docker / PaaS add-ons (on host) <a class="header-anchor" href="#docker-paas-add-ons-on-host" aria-label="Permalink to &quot;Docker / PaaS add-ons (on host)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Script path</th><th>Notes</th></tr></thead><tbody><tr><td>Dockge</td><td><code>tools/addon/dockge.sh</code></td><td>Compose stack manager</td></tr><tr><td>Coolify</td><td><code>tools/addon/coolify.sh</code></td><td>Self-hosted PaaS</td></tr><tr><td>Komodo</td><td><code>tools/addon/komodo.sh</code></td><td>Build/deploy Docker workloads</td></tr></tbody></table><hr><h2 id="default-vs-advanced-mode" tabindex="-1">Default vs advanced mode <a class="header-anchor" href="#default-vs-advanced-mode" aria-label="Permalink to &quot;Default vs advanced mode&quot;">​</a></h2><ul><li><strong>Default</strong> — Uses script-defined CPU, RAM, and disk defaults; minimal prompts. Most installs finish in a few minutes.</li><li><strong>Advanced</strong> — Exposes storage pool, network bridge, resource sizing, and app-specific options before creation.</li></ul><h2 id="after-install" tabindex="-1">After install <a class="header-anchor" href="#after-install" aria-label="Permalink to &quot;After install&quot;">​</a></h2><p>Many application scripts install a <strong>post-install menu</strong> inside the LXC (updates, settings, logs). Open the container console from the Proxmox UI and follow the on-screen helper.</p><h2 id="related-docs-in-this-repo" tabindex="-1">Related docs in this repo <a class="header-anchor" href="#related-docs-in-this-repo" aria-label="Permalink to &quot;Related docs in this repo&quot;">​</a></h2><ul><li><a href="./../../../microcontrollers-and-socs/raspberry-pi/install-proxmox-on-a-raspberry-pi/README.html">Install ProxMox on a Raspberry Pi</a> — Pi-focused Proxmox installs (PXVirt / Pimox / guides)</li><li><a href="./../../resize-proxmox-root-storage.html">Resize Proxmox root storage</a></li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li><strong>community-scripts.org</strong> is the catalog; <strong>github.com/community-scripts/ProxmoxVE</strong> is the source of truth for script paths.</li><li>One command from the Proxmox <strong>host shell</strong> creates an LXC or VM — no manual template hunting.</li><li><strong>Nginx Proxy Manager</strong> (<code>ct/nginxproxymanager.sh</code>) is the go-to reverse-proxy UI; pair with <strong>post-pve-install</strong> on new nodes.</li><li>Use <strong>Default</strong> for quick homelab wins; <strong>Advanced</strong> when you care about bridge, storage, or sizing.</li><li>Browse <a href="https://community-scripts.org/categories" target="_blank" rel="noreferrer">categories</a> for the full list — new scripts ship frequently (RSS: <code>https://community-scripts.org/api/rss</code>).</li></ul>',50)])])}const g=e(i,[["render",d]]);export{u as __pageData,g as default};
